Rule.Source:
import sailpoint.tools.Util;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.Filter;
  import sailpoint.object.Link;

  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  Log logger = LogFactory.getLog("Ascension.Rule.Correlation.CernerSnow");
  try{
  logger.debug("Ascension.Rule.Correlation.CernerSnow Starting");
  Map result = new HashMap();
  Identity tempIdentity = null;

  String userId = account.getStringAttribute("User ID");


  if(Util.isNotNullOrEmpty(userId)){ 
    QueryOptions op = new QueryOptions();
    op.add(Filter.ignoreCase(Filter.eq("samAccountName", userId)));
    Iterator itr = context.search(Identity.class, op);
    if (!Util.isEmpty(itr)) {
      while (itr.hasNext()) {
        tempIdentity = (Identity) itr.next();
        result.put("identityName", tempIdentity.getName());
//        context.decache(tempIdentity);
        return result;
      }
      Util.flushIterator(itr);
    }

    logger.debug("SamAccountName Check Done");
    //employee ID
    String empId = account.getStringAttribute("employee ID");
    if( Util.isNotNullOrEmpty(empId) && Util.isNullOrEmpty(result.get("identityName")) ){
      QueryOptions opEmpID = new QueryOptions();
      opEmpID.add(Filter.ignoreCase(Filter.eq("employeeId", empId)));
      Iterator itrEmpID = context.search(Identity.class, opEmpID);
      if (!Util.isEmpty(itrEmpID)) {
        while (itrEmpID.hasNext()) {
          tempIdentity = (Identity) itrEmpID.next();
          result.put("identityName", tempIdentity.getName());
//          context.decache(tempIdentity);
          return result;
        }
        Util.flushIterator(itrEmpID);
      }

    }
    logger.debug("EmpId Check Done");

    //all ad link
    if( Util.isNullOrEmpty(result.get("identityName")) ){
      QueryOptions ops = new QueryOptions();
      ops.addFilter(Filter.like("links.displayName", userId, Filter.MatchMode.END));
      Iterator itrID = context.search(Identity.class,ops,"name");
      if (!Util.isEmpty(itrID)) {
        while (Util.isNullOrEmpty(result.get("identityName")) && itrID.hasNext()) {
          Object[] currentUser = (Object[]) itrID.next();       	
          if(currentUser != null && currentUser[0] != null) {
            tempIdentity = context.getObjectByName(Identity.class, currentUser[0].toString());
            if(tempIdentity!=null){
              List<Link> linkList = tempIdentity.getLinks();
              if(!Util.isEmpty(linkList)){
                for(Link tempLink : linkList){
                  if(Util.nullSafeCaseInsensitiveEq(tempLink.getApplication().getType(), "Active Directory - Direct")){
                    if(tempLink.getAttribute("sAMAccountName") !=null && Util.nullSafeCaseInsensitiveEq( tempLink.getAttribute("sAMAccountName").toString(), userId)){
                      result.put("identityName", tempIdentity.getName());
                      return result;
                    }
                  }
                }
              }
//              context.decache(tempIdentity);
            }
          }
        }
        Util.flushIterator(itrID);
      }
    }
  }

  logger.debug("Ascension.Rule.Correlation.CernerSnow Exiting");
  }catch(Exception e){
     logger.error("Exception in Ascension-Rule-Correlation-CernerSnow: ",e);
  }
  return result;
